// Read tickers from upstream node or hardcode for testing
const input = $input.first().json;
const tickers = input?.tickers || ['PETR4', 'VALE3'];
return tickers.map(t => ({ ticker: String(t).trim().toUpperCase() }));

const ticker = $input.first().json.ticker;
const response = $input.first().json;
const data = response.data || [];
if (!data.length) return [];

const d = data[0].d || [];
if (!d || d.length < 13) return [];

const toFloat = (v) => (v === null || v === '' ? null : parseFloat(v));
const toInt = (v) => {
  if (v === null || v === '') return null;
  const n = parseFloat(v);
  return isNaN(n) ? null : Math.round(n);
};

const volume = toInt(d[6]);
const avg30 = toInt(d[8]);
let volumeChangeRatio = null;
if (volume && avg30) volumeChangeRatio = volume / avg30;

return [{
  json: {
    site: "bestchoice",
    source: "volume",
    ticker: String(d[0] || '').trim().toUpperCase(),
    tipo: 'stock',
    description: d[1],
    exchange: d[3],
    close: toFloat(d[4]),
    change: toFloat(d[5]),
    volume,
    volume_change: toFloat(d[7]),
    volume_change_ratio: volumeChangeRatio,
    average_volume_30d: avg30,
    average_volume_10d: toInt(d[9]),
    recommendation_mark: toFloat(d[10]),
    net_margin_fy: toFloat(d[11]),
    dividends_yield_current: toFloat(d[12])
  }
}];
